diff --git a/llvm/lib/Transforms/InstCombine/InstCombineSelect.cpp b/llvm/lib/Transforms/InstCombine/InstCombineSelect.cpp
index 394dfca262e1..3be052165bbf 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineSelect.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineSelect.cpp
@@ -3721,9 +3721,25 @@ Instruction *InstCombinerImpl::visitSelectInst(SelectInst &SI) {
     if (Instruction *IV = foldSelectOpOp(SI, TI, FI))
       return IV;

+  // select c2, (select c1, a, b), (select c1, b, a) -> select (xor c1, c2), b, a
+  // select c2, (select c1, b, a), (select c1, a, b) -> select (xor c1, c2), b, a
+  SelectInst *TrueSI, *FalseSI;
+  if (match(TrueVal, m_OneUse(m_Select(m_Value(), m_Value(), m_Value()))) &&
+      match(FalseVal, m_OneUse(m_Select(m_Value(), m_Value(), m_Value())))) {
+    TrueSI = cast<SelectInst>(TrueVal);
+    FalseSI = cast<SelectInst>(FalseVal);
+    Value *InnerCond = TrueSI->getCondition();
+    if (InnerCond == FalseSI->getCondition() &&
+        TrueSI->getTrueValue() == FalseSI->getFalseValue() &&
+        TrueSI->getFalseValue() == FalseSI->getTrueValue() &&
+        InnerCond->getType() == CondVal->getType()) {
+      Value *Xor = Builder.CreateXor(InnerCond, CondVal);
+      return SelectInst::Create(Xor, TrueSI->getFalseValue(), TrueSI->getTrueValue());
+    }
+  }
+
   if (Instruction *I = foldSelectExtConst(SI))
     return I;
-
   if (Instruction *I = foldSelectWithSRem(SI, *this, Builder))
     return I;

log.source_program:
define i32 @select_of_symmetric_selects(i32 %a, i32 %b, i1 %c1, i1 %c2) {
  %sel1 = select i1 %c1, i32 %a, i32 %b
  %sel2 = select i1 %c1, i32 %b, i32 %a
  %ret = select i1 %c2, i32 %sel1, i32 %sel2
  ret i32 %ret
}

